import{_ as r,o as t,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"01-2 散裝航運產業結構","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-2_散裝航運.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-2_散裝航運.md"}'),n={name:"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-2_散裝航運.md"};function e(o,a,s,g,d,m){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="_01-2-散裝航運產業結構" tabindex="-1">01-2 散裝航運產業結構 <a class="header-anchor" href="#_01-2-散裝航運產業結構" aria-label="Permalink to &quot;01-2 散裝航運產業結構&quot;">​</a></h1><h2 id="一、四大船型分類" tabindex="-1">一、四大船型分類 <a class="header-anchor" href="#一、四大船型分類" aria-label="Permalink to &quot;一、四大船型分類&quot;">​</a></h2><p>散裝航運（Dry Bulk Shipping）以無包裝大宗貨物為主，依船體大小分為四大類：</p><h3 id="_1-capesize-好望角型" tabindex="-1">1. Capesize（好望角型） <a class="header-anchor" href="#_1-capesize-好望角型" aria-label="Permalink to &quot;1. Capesize（好望角型）&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：80,000～175,000 DWT（平均約 156,000 DWT，部分可達 400,000+ DWT）</li><li><strong>尺寸</strong>：約 290m × 45m，吃水約 18m</li><li><strong>特點</strong>：船體過大無法通過巴拿馬運河（原航道）或蘇伊士運河，必須繞行好望角或合恩角</li><li><strong>主要貨物</strong>：鐵礦砂、煤炭（動力煤）</li><li><strong>典型航線</strong>：巴西/澳洲/南非 → 中國；南非 → 歐洲</li><li><strong>子類型</strong>：VLOC（超大型礦石運輸船）、VLBC（超大型散貨船）</li></ul><h3 id="_2-panamax-巴拿馬型" tabindex="-1">2. Panamax（巴拿馬型） <a class="header-anchor" href="#_2-panamax-巴拿馬型" aria-label="Permalink to &quot;2. Panamax（巴拿馬型）&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：65,000～80,000 DWT（原巴拿馬型）；New Panamax 可達 120,000 DWT</li><li><strong>尺寸</strong>：原巴拿馬最大 294m × 32.3m，吃水 12m</li><li><strong>特點</strong>：設計符合原巴拿馬運河船閘最大尺寸，2016 年新航道擴建後出現 New Panamax（Neopanamax）級別</li><li><strong>主要貨物</strong>：煤炭、穀物、鋼製品、林產品、肥料等</li><li><strong>附加能力</strong>：部分可載運約 5,000 TEU 貨櫃</li></ul><h3 id="_3-supramax-超巴拿馬型" tabindex="-1">3. Supramax（超巴拿馬型） <a class="header-anchor" href="#_3-supramax-超巴拿馬型" aria-label="Permalink to &quot;3. Supramax（超巴拿馬型）&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：45,000～60,000 DWT</li><li><strong>尺寸</strong>：150～200m × 約 30m，吃水約 13m</li><li><strong>特點</strong>：配備 4～5 台吊車（25～40mt 起重能力），可停靠基礎設施較弱的港口</li><li><strong>貨物</strong>：散裝礦石、水泥、穀物、鋼管等；通常 5 個貨艙，可同時裝載不同貨物</li><li><strong>優勢</strong>：靈活性高，雙殼結構為主流新船設計</li></ul><h3 id="_4-handysize-手型" tabindex="-1">4. Handysize（手型） <a class="header-anchor" href="#_4-handysize-手型" aria-label="Permalink to &quot;4. Handysize（手型）&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：10,000～35,000 DWT</li><li><strong>特點</strong>：最小型散貨船，可進入全球多數港口（含淺水港）</li><li><strong>主要貨物</strong>：小宗散貨、肥料、糖、木片等</li></ul><h2 id="二、主要貨物" tabindex="-1">二、主要貨物 <a class="header-anchor" href="#二、主要貨物" aria-label="Permalink to &quot;二、主要貨物&quot;">​</a></h2><ul><li><strong>鐵礦砂</strong>：Capesize 主力貨物，中國為最大進口國（澳洲、巴西供應）</li><li><strong>煤炭</strong>：動力煤（發電用）→ Capesize/Panamax；焦煤（鋼鐵用）</li><li><strong>穀物</strong>：黃豆、玉米、小麥 → Panamax/Supramax</li><li><strong>其他散貨</strong>：水泥、肥料、鋼製品、木片、鋁土礦等</li></ul><h2 id="三、bdi-指數-baltic-dry-index" tabindex="-1">三、BDI 指數（Baltic Dry Index） <a class="header-anchor" href="#三、bdi-指數-baltic-dry-index" aria-label="Permalink to &quot;三、BDI 指數（Baltic Dry Index）&quot;">​</a></h2><ul><li><strong>定義</strong>：由倫敦 Baltic Exchange 每日發布的綜合運價指數</li><li><strong>構成</strong>：加權平均 Capesize（58%）、Panamax（36%）、Supramax（6%）的即期運費</li><li><strong>經濟指標意義</strong>：反映散貨船供需平衡，被視為全球經濟成長與工業生產的領先指標</li><li><strong>2025 年表現</strong>：全年 BDI 下跌 4.2%（年對年），主要受年初疲軟影響；Capesize 跌幅最明顯</li><li><strong>2026 年展望</strong>：散貨船供應增長約 2.6%（Panamax/Supramax 交船為主），需求增長預估 1～2%；鐵礦砂貿易流仍具支撐，但中國鋼鐵需求放緩限制整體漲幅</li></ul><blockquote><p>資料來源：Clarksons Glossary、Wikipedia — Capesize/Panamax/Supramax/Baltic Dry Index、Gerdau Market Update、Intermanager 2025/2026 散貨市場展望報告、BIMCO Dry Bulk Outlook</p></blockquote>',16)])])}const _=r(n,[["render",e]]);export{h as __pageData,_ as default};
